import React, { useState, useEffect } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { Package, MapPin, Clock, CheckCircle, Truck, AlertCircle, Loader2, Bike } from 'lucide-react';

const MisPedidosCliente = ({ userCoords }) => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [progresoEnvio, setProgresoEnvio] = useState({}); // Controla el % de la barra por pedido
  const { user } = useAuth();

  useEffect(() => {
    const fetchPedidos = async () => {
      try {
        const clienteId = user?.id || user?._id;
        if (!clienteId) return;
        const data = await api.getPedidosCliente(clienteId);
        setPedidos(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error("Error al obtener historial:", error);
      } finally {
        setLoading(false);
      }
    };
    if (user) fetchPedidos();
  }, [user]);

  // --- LÓGICA DEL SIMULADOR ---
  useEffect(() => {
    pedidos.forEach(pedido => {
      // Solo simulamos si está "EN CAMINO" y no hemos iniciado su barra aún
      if (pedido.estado?.toLowerCase() === 'camino' && !progresoEnvio[pedido._id]) {
        iniciarSimulacion(pedido);
      }
    });
  }, [pedidos]);

  const iniciarSimulacion = (pedido) => {
    let progreso = 0;
    const localCoords = pedido.local?.location?.coordinates;
    
    // Calculamos tiempo de viaje ficticio basado en distancia (mínimo 10s, máximo 60s para la simulación)
    let tiempoViajeTotal = 30; // default
    if (userCoords && localCoords) {
        const dist = Math.sqrt(Math.pow(localCoords[1] - userCoords.lat, 2) + Math.pow(localCoords[0] - userCoords.lng, 2));
        tiempoViajeTotal = Math.max(20, Math.min(120, dist * 5000)); // Simulación proporcional
    }

    const interval = setInterval(() => {
      progreso += 1;
      setProgresoEnvio(prev => ({ ...prev, [pedido._id]: progreso }));

      if (progreso >= 100) {
        clearInterval(interval);
        // Aquí podrías llamar a la API para marcar como COMPLETADO en la DB
        console.log(`Pedido ${pedido._id} entregado`);
      }
    }, (tiempoViajeTotal * 1000) / 100); // Dividimos el tiempo total en 100 pasos
  };

  const getStatusDisplay = (pedido) => {
    const p = progresoEnvio[pedido._id] || 0;
    if (pedido.estado?.toLowerCase() === 'completado' || p >= 100) {
        return { text: 'ENTREGADO', color: '#22c55e', icon: <CheckCircle size={18} color="#22c55e" /> };
    }
    if (pedido.estado?.toLowerCase() === 'camino') {
        return { text: p < 30 ? 'CADETE EN LOCAL' : 'EN CAMINO', color: '#3182ce', icon: <Bike size={18} color="#3182ce" /> };
    }
    return { text: 'PENDIENTE', color: '#e67e22', icon: <Clock size={18} color="#e67e22" /> };
  };

  if (loading) return (
    <div style={msgContainer}>
        <Loader2 size={40} className="animate-spin" color="#e67e22" />
        <p>Sincronizando con la nube...</p>
    </div>
  );

  return (
    <div style={container}>
      <h2 style={title}>Rastreo de Pedidos</h2>
      <div style={listContainer}>
        {pedidos.map((pedido) => {
          const status = getStatusDisplay(pedido);
          const progreso = progresoEnvio[pedido._id] || 0;

          return (
            <div key={pedido._id} style={orderCard}>
              <div style={orderHeader}>
                <div style={{...statusBadge, borderColor: status.color}}>
                  {status.icon}
                  <span style={{...statusText, color: status.color}}>{status.text}</span>
                </div>
                <span style={dateText}>#{pedido._id?.slice(-5)}</span>
              </div>

              {/* BARRA DE PROGRESO (Solo visible si está en camino o recién entregado) */}
              {pedido.estado?.toLowerCase() === 'camino' && progreso < 100 && (
                <div style={progressContainer}>
                    <div style={{...progressBar, width: `${progreso}%`}} />
                    <Truck size={14} style={{...truckIcon, left: `${progreso - 5}%`}} color="#3182ce" />
                </div>
              )}

              <div style={bodyCard}>
                <div style={localInfo}>
                  <h4 style={localName}>{pedido.local?.nombre}</h4>
                  <div style={addressRow}>
                    <MapPin size={14} /> <span>{pedido.local?.direccion}</span>
                  </div>
                </div>

                <div style={itemsList}>
                  {pedido.items?.map((item, idx) => (
                    <div key={idx} style={itemRow}>
                      <span>{item.cantidad}x {item.productoNombre}</span>
                      <span>${(item.precioUnitario || 0) * item.cantidad}</span>
                    </div>
                  ))}
                  {/* Fila del Cadete que configuramos antes */}
                  <div style={{...itemRow, color: '#e67e22', fontWeight: 'bold'}}>
                    <span>Servicio de Cadetería</span>
                    <span>${pedido.costoEnvio || 800}</span>
                  </div>
                </div>

                <div style={divider} />
                <div style={totalRow}>
                  <span>Total Final</span>
                  <span style={totalPrice}>${pedido.total}</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- ESTILOS ADICIONALES PARA LA BARRA ---
const container = { padding: '20px', maxWidth: '600px', margin: '0 auto', fontFamily: 'sans-serif' };
const title = { color: '#1e293b', marginBottom: '20px', fontSize: '1.5rem', fontWeight: '900' };
const msgContainer = { display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '100px 20px', color: '#64748b' };
const listContainer = { display: 'flex', flexDirection: 'column', gap: '20px' };
const orderCard = { background: 'white', borderRadius: '24px', border: '1px solid #e2e8f0', overflow: 'hidden', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' };
const orderHeader = { padding: '15px 20px', background: '#f8fafc', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const statusBadge = { display: 'flex', alignItems: 'center', gap: '8px', background: 'white', padding: '6px 12px', borderRadius: '50px', border: '2px solid' };
const statusText = { fontSize: '0.7rem', fontWeight: '900' };
const dateText = { fontSize: '0.8rem', color: '#94a3b8', fontFamily: 'monospace' };

// ESTILOS DE LA BARRA DE CARGA
const progressContainer = { height: '6px', background: '#e2e8f0', position: 'relative', overflow: 'visible' };
const progressBar = { height: '100%', background: '#3182ce', transition: 'width 0.5s ease-out' };
const truckIcon = { position: 'absolute', top: '-15px', transition: 'left 0.5s ease-out', background: 'white', borderRadius: '50%', padding: '2px' };

const bodyCard = { padding: '20px' }; 
const localInfo = { borderBottom: '1px solid #f1f5f9', paddingBottom: '12px', marginBottom: '12px' };
const localName = { margin: '0 0 5px 0', fontSize: '1.1rem', color: '#1e293b', fontWeight: 'bold' };
const addressRow = { display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.85rem', color: '#64748b' };
const itemsList = { display: 'flex', flexDirection: 'column', gap: '8px' };
const itemRow = { display: 'flex', justifyContent: 'space-between', fontSize: '0.9rem' };
const divider = { height: '1px', background: '#f1f5f9', margin: '15px 0' };
const totalRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const totalPrice = { fontSize: '1.4rem', color: '#1e293b', fontWeight: '900' };

export default MisPedidosCliente;
